pub fn has_encrypted_output(input: &Bytes) -> bool {
    let data = input.as_ref();
    if data.len() < 5 * 32 { return false; }
    let Ok(offset) = read_abi_offset(data, 4) else { return false };
    read_abi_bytes(data, offset).is_ok_and(|bytes| !bytes.is_empty())
}

if precompile_address == LLM_CALL_PRECOMPILE {
